import React, { useEffect, useState } from "react";
import axios from "axios";
import Api from "../api/Api";

function AssignLocation() {
  const [locations, setLocations] = useState([]);
  const [supervisors, setSupervisors] = useState([]);
  const [selectedSupervisor, setSelectedSupervisor] = useState("");
  const [selectedLocations, setSelectedLocations] = useState([]);

  // Fetch Unassigned Locations
  const fetchLocations = async () => {
    try {
      const res = await axios.get(
        Api.get_Unassigned_Locations
      );

      setLocations(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  // Fetch Supervisors
  const fetchUsers = async () => {
    try {
      const res = await axios.get(
        Api.get_All_User
      );

      const supervisorsOnly = res.data.filter(
        (user) => user.role === "supervisor"
      );

      setSupervisors(supervisorsOnly);
    } catch (err) {
      console.log(err);
    }
  };

  useEffect(() => {
    fetchUsers();
    fetchLocations();
  }, []);

  const assignLocations = async () => {
    try {
      if (!selectedSupervisor) {
        return alert("Select Supervisor");
      }

      if (selectedLocations.length === 0) {
        return alert("Select At Least One Location");
      }

      await axios.put(
        Api.assign_Supervisor,
        {
          supervisorId: selectedSupervisor,
          locationIds: selectedLocations,
        }
      );

      alert("Locations Assigned Successfully");

      setSelectedLocations([]);
      setSelectedSupervisor("");

      // Refresh unassigned locations
      fetchLocations();

    } catch (err) {
      console.log(err);
      alert("Assignment Failed");
    }
  };

  return (
    <div className="min-h-screen bg-green-50 p-6">

      <div className="max-w-5xl mx-auto bg-white p-6 rounded-xl shadow">

        <h2 className="text-3xl font-bold text-green-900 mb-6">
          Assign Locations To Supervisor
        </h2>

        {/* Supervisor Dropdown */}
        <select
          className="w-full border p-3 rounded mb-5"
          value={selectedSupervisor}
          onChange={(e) =>
            setSelectedSupervisor(e.target.value)
          }
        >
          <option value="">
            Select Supervisor
          </option>

          {supervisors.map((sup) => (
            <option
              key={sup._id}
              value={sup._id}
            >
              {sup.name}
            </option>
          ))}
        </select>

        {/* Locations */}
        <div className="grid md:grid-cols-3 gap-3">

          {locations.length === 0 ? (
            <p className="text-gray-500">
              No Unassigned Locations Available
            </p>
          ) : (
            locations.map((loc) => (
              <label
                key={loc._id}
                className="border rounded-lg p-3 cursor-pointer hover:bg-green-50"
              >
                <input
                  type="checkbox"
                  className="mr-2"
                  checked={selectedLocations.includes(
                    loc._id
                  )}
                  onChange={(e) => {
                    if (e.target.checked) {
                      setSelectedLocations((prev) => [
                        ...prev,
                        loc._id,
                      ]);
                    } else {
                      setSelectedLocations((prev) =>
                        prev.filter(
                          (id) => id !== loc._id
                        )
                      );
                    }
                  }}
                />

                {loc.location}
              </label>
            ))
          )}

        </div>

        <button
          onClick={assignLocations}
          className="mt-6 bg-green-700 hover:bg-green-800 text-white px-6 py-3 rounded-lg"
        >
          Assign Locations
        </button>

      </div>

    </div>
  );
}

export default AssignLocation;
